#include <bits/stdc++.h>
using namespace std;

const int N=2010;

int n,P,W,ap[N],bp[N],as[N],bs[N],q[N],hh,tt;
long long f[N][N];

int main(){
    scanf("%d%d%d",&n,&P,&W);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d%d",&ap[i],&bp[i],&as[i],&bs[i]);
    memset(f,0xcf,sizeof(f));
    f[n+1][0]=0;
    for(int i=n;i;i--){
        for(int j=0;j<=P;j++)
            f[i][j]=f[i+1][j];
        int x=min(n+1,i+W+1);
        hh=1,tt=0;
        for(int j=0;j<=P;j++){
            while(hh<=tt && q[hh]<j-bs[i]) hh++;
            while(hh<=tt && f[x][q[tt]]-q[tt]*bp[i]<=f[x][j]-j*bp[i]) tt--;
            q[++tt]=j;
            f[i][j]=max(f[i][j],f[x][q[hh]]+(j-q[hh])*bp[i]);
        }
        hh=1,tt=0;
        for(int j=P;j>=0;j--){
            while(hh<=tt && q[hh]>j+as[i]) hh++;
            while(hh<=tt && f[x][q[tt]]-q[tt]*ap[i]<=f[x][j]-j*ap[i]) tt--;
            q[++tt]=j;
            f[i][j]=max(f[i][j],f[x][q[hh]]-(q[hh]-j)*ap[i]);
        }
    }
    printf("%lld",f[1][0]);
    return 0;
}
